&lt; Zoj3229 Shoot the Bullet|东方文花帖|【模板】有源汇上下界最大流 - 洛谷 &gt;

先bfs分层

2.dfs增广，当前弧优化

重复以上步骤

#include&lt;bits/stdc++.h&gt;using namespace std;#define int long longinline int read()&#123;int x=0,f=1;char ch=getchar();while(ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if(ch==&#x27;-&#x27;)f=-1;ch=getchar();&#125;while(ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=(x&lt;&lt;1)+(x&lt;&lt;3)+(ch^48);ch=getchar();&#125;return x*f;&#125;#define Z(x) (x)*(x)#define pb push_back//#define M//#define mo#define N 500010struct node &#123;	int x, y, z, n; &#125;d[N];int n, m, i, j, k;int h[N], H[N], dep[N]; int u, v, w, S, T, ans; queue&lt;int&gt;q;  void cun(int x, int y, int z) &#123;//	printf(&quot;%lld %lld %lld\n&quot;, x, y, z); 	d[++k].x=x; d[k].y=y; d[k].z=z; 	 d[k].n=h[x]; h[x]=k;&#125; int bfs() &#123;	while(!q.empty()) q.pop(); 	memset(dep, -1, sizeof(dep)); 	memcpy(h, H, sizeof(H)); 	dep[S]=1; q.push(S); 	while(!q.empty()) &#123;		u=q.front(); q.pop(); //		printf(&quot;%d %d\n&quot;, u, h[u]); 		for(int g=h[u]; g; g=d[g].n) &#123;			v=d[g].y; w=d[g].z; //			printf(&quot;%lld %lld\n&quot;, v, w); 			if(w&lt;=0 || dep[v]!=-1) continue; 			dep[v]=dep[u]+1; q.push(v); 		&#125;	&#125;//	printf(&quot;--------------%lld\n&quot;, dep[T]); 	return dep[T]!=-1; &#125; int dfs(int x, int w) &#123;	if(x==T) return w;	if(!w) return 0; 	int ans=0, s; 	for(int &amp;i=h[x]; i; i=d[i].n) &#123;		int y=d[i].y, z=d[i].z;  		if(dep[y]!=dep[x]+1) continue; 		if(z&lt;=0) continue; 		s=dfs(y, min(w, z)); ans+=s; w-=s; 		d[i].z-=s; d[i^1].z+=s; 		if(!w) break;  	&#125;	return ans; &#125; signed main()&#123;//	freopen(&quot;in.txt&quot;, &quot;r&quot;, stdin);//	freopen(&quot;out.txt&quot;, &quot;w&quot;, stdout);//	srand(time(NULL));//	T=read();//	while(T--) &#123;////	&#125;	n=read(); m=read(); S=read(); T=read(); 	for(i=1, k=1; i&lt;=m; ++i) &#123;		u=read(); v=read(); w=read(); 		cun(u, v, w); cun(v, u, 0); 	&#125;	memcpy(H, h, sizeof(h)); 	while(bfs()) ans+=dfs(S, 1e18); 	printf(&quot;%lld&quot;, ans); 	return 0;&#125;
如果加了当前弧优化，dfs中循环里直接返回或最后返回复杂度是一样的。

珂朵莉树维护并查集：CF1725K

本文搬运自本人高中时期CSDN博客，若图片加载不出来，可到原文查看：https://blog.csdn.net/zhangtingxiqwq/article/details/133607729

https://codeforces.com/problemset/problem/1725/K
发现题目涉及值域的区间覆盖，可以考虑对值域维护珂朵莉树（应该是类似珂朵莉树思想的东西）。
但要把值域对应回原位置，我们可以拿并查集维护。
#include&lt;bits/stdc++.h&gt;using namespace std;//#define int long longinline int read()&#123;int x=0,f=1;char ch=getchar(); while(ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if(ch==&#x27;-&#x27;)f=-1;ch=getchar();&#125;while(ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=(x&lt;&lt;1)+(x&lt;&lt;3)+(ch^48);ch=getchar();&#125;return x*f;&#125;#define Z(x) (x)*(x)#define pb push_back//mt19937 rand(time(0));//mt19937_64 rand(time(0));//srand(time(0));#define N 5000010//#define M//#define mostruct node &#123;	int x, id; 	bool operator &lt;(const node &amp;A) const &#123;		if(x==A.x) return id&lt;A.id; 		return x&lt;A.x; 	&#125;&#125;;int n, m, i, j, k, T;set&lt;node&gt;s; set&lt;node&gt;::iterator it1, it2, it; int f[N], p[N], a[N], l, r, q, w, mid, op; int fa(int x) &#123;	if(f[x]==x) return x; 	return f[x]=fa(f[x]); &#125;signed main()&#123;//	freopen(&quot;in.txt&quot;, &quot;r&quot;, stdin);//	freopen(&quot;out.txt&quot;, &quot;w&quot;, stdout);//	T=read();//	while(T--) &#123;////	&#125;	n=read(); 	for(i=1; i&lt;=n; ++i) &#123;		a[i]=read(); s.insert(&#123;a[i], i&#125;); 		p[i]=i; f[i]=i; 	&#125;//	for(it=s.begin(); it!=s.end(); ++it) printf(&quot;%d(%d) &quot;, it-&gt;x, it-&gt;id); //	printf(&quot;\n&quot;); 	q=read(); 	auto work = [&amp;] (int l, int r, int k) -&gt; void&#123;//		printf(&quot;[%d %d] =&gt; %d\n&quot;, l, r, k); 		a[++n]=k; f[n]=n; s.insert(&#123;a[n], n&#125;); 		it1=it=s.lower_bound(&#123;l, 0&#125;), it2=s.lower_bound(&#123;r+1, 0&#125;); //		printf(&quot;&gt; %d(%d) %d(%d)\n&quot;, it1-&gt;id, it1-&gt;x, it2-&gt;id, it2-&gt;x); 		for(; it1!=it2; ++it1) &#123;//			printf(&quot;%d -&gt; %d\n&quot;, it1-&gt;id, n); 			f[fa(it1-&gt;id)]=fa(n); 		&#125;		s.erase(it, it2); 	&#125;; 		while(q--) &#123;		op=read(); 		if(op==1) &#123;			k=read(); w=read(); 			p[k]=++n; a[n]=w; f[n]=n; 			s.insert(&#123;a[n], n&#125;); 		&#125;		if(op==2) &#123;			k=read(); 			printf(&quot;%lld\n&quot;, a[fa(p[k])]); 		&#125;		if(op==3) &#123;			l=read(); r=read(); 			mid=(l+r)/2; 			work(l, mid, l-1); 			work(mid+1, r, r+1); 		&#125;//		for(it=s.begin(); it!=s.end(); ++it) printf(&quot;%d(%d) &quot;, it-&gt;x, it-&gt;id); //		printf(&quot;\n&quot;); 	&#125;	return 0;&#125;

质因子拆贡献+朴素容斥：1007T3

本文搬运自本人高中时期CSDN博客，若图片加载不出来，可到原文查看：https://blog.csdn.net/zhangtingxiqwq/article/details/133697910

http://cplusoj.com/d/senior/p/SS231007C
考虑枚举gcd，然后容斥，恰好转至少。 ggg 表示gcd恰好为 ddd ， fff 表示至少为 ddd
显然有 f(d)=∑d∣ng(n)f(d)=\sum_{d|n}g(n)f(d)=∑d∣n​g(n) ，可以直接莫反成： g(d)=∑d∣nf(n)μ(nd)g(d)=\sum_{d|n}f(n)^{\mu( {\frac n d })}
g(d)=∑d∣n​f(n)μ(dn​) ，但其实不用这么麻烦。从大往小处理 ddd ，则 
考虑如何计算 fff ，直接上拆贡献。枚举每个质因子。对于 ddd 我们可以直接计算。对于 pcp^cpc 的东西，我们要保证 
直接算很麻烦。考虑容，然后发现不用容，直接恰好转至少后变差分就行了。
#include&lt;bits/stdc++.h&gt;using namespace std;#define int long longinline int read()&#123;int x=0,f=1;char ch=getchar(); while(ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if(ch==&#x27;-&#x27;)f=-1;ch=getchar();&#125;while(ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=(x&lt;&lt;1)+(x&lt;&lt;3)+(ch^48);ch=getchar();&#125;return x*f;&#125;#define Z(x) (x)*(x)#define pb push_back//mt19937 rand(time(0));//mt19937_64 rand(time(0));//srand(time(0));#define N 2000010//#define M#define mo 998244353int pw(int a, int b) &#123;	int ans=1; 	while(b) &#123;		if(b&amp;1) ans*=a; 		a*=a; b&gt;&gt;=1; 		ans%=mo; a%=mo; 	&#125;	return ans; &#125;int pw(int a, int b, int p) &#123;	int ans=1; 	while(b) &#123;		if(b&amp;1) ans*=a; 		a*=a; b&gt;&gt;=1; 		ans%=p; a%=p; 	&#125;	return ans; &#125;int fac[N], inv[N], ifac[N]; void init(int n) &#123;	int i; 	for(i=fac[0]=1; i&lt;=n; ++i) fac[i]=fac[i-1]*i%mo; 	ifac[n]=pw(fac[n], mo-2); 	for(i=n-1; i&gt;=0; --i) ifac[i]=ifac[i+1]*(i+1)%mo;     for(i=1; i&lt;=n; ++i) inv[i]=ifac[i]*fac[i-1]%mo; &#125;int C(int n, int m) &#123;	if(m&gt;n) return 0;	return fac[n]*ifac[m]%mo*ifac[n-m]%mo; &#125;void Add(int &amp;a, int b) &#123;	a+=b; if(a&gt;=mo || a&lt;=-mo) a%=mo;     if(a&lt;0) a+=mo; &#125;void Mul(int &amp;a, int b) &#123;	a*=b; if(a&gt;=mo || a&lt;=-mo) a%=mo;     if(a&lt;0) a+=mo; &#125;void Mod(int &amp;a) &#123;	if(a&gt;=mo || a&lt;=-mo) a%=mo;     if(a&lt;0) a+=mo; &#125;void Mod(int &amp;a, int p) &#123;	if(a&gt;=p || a&lt;=-p) a%=p;     if(a&lt;0) a+=p; &#125;void Add(int &amp;a, int b, int p) &#123;	a+=b; if(a&gt;=p || a&lt;=-p) a%=p;     if(a&lt;0) a+=p; &#125;const int iv2=pw(2, mo-2); int b[N]; vector&lt;int&gt;z; void prim(int n) &#123;	memset(b, -1, sizeof(b)); b[1]=0;  	for(int i=2; i&lt;=n; ++i) &#123;		if(b[i]) z.pb(i); 		for(int j : z) &#123;			if(i*j&gt;n) break; 			b[j*i]=0; if(i%j==0) break; 		&#125;	&#125;&#125;int n, m, i, j, k, T;int ans, lim, lstlim, d, D, g[N], f[N], c, p, P; int S[N], s[N]; signed main()&#123;//	freopen(&quot;in.txt&quot;, &quot;r&quot;, stdin);//	freopen(&quot;out.txt&quot;, &quot;w&quot;, stdout);		freopen(&quot;number.in&quot;, &quot;r&quot;, stdin);	freopen(&quot;number.out&quot;, &quot;w&quot;, stdout);//	T=read();//	while(T--) &#123;////	&#125;	n=read(); m=read(); init(2000000); 	prim(2000000); 	lstlim=0; ans=1; 	for(d=m; d&gt;=1; --d) &#123;		lim=m/d; //		if(lim==lstlim) &#123;//			f[d]=f[d+1]; g[d]=g[d+1];//		&#125;//		else &#123;			f[d]=pw(d, pw(lim, n, mo-1)); 			for(auto p : z) &#123;				if(p&gt;lim) break; //				printf(&quot;%lld : \n&quot;, p); 				for(c=0, P=1; P&lt;=lim; P*=p, ++c) &#123;					S[c]=pw(lim-lim/(P*p), n, mo-1); //					printf(&quot;S %lld : %lld %lld\n&quot;, c, S[c], lim-lim/(P+1)); 				&#125;				for(c=1, P=p; P&lt;=lim; P*=p, ++c) &#123;					s[c]=S[c]-S[c-1]; Mod(s[c], mo-1); //					printf(&quot;s %lld : %lld\n&quot;, c, s[c]); 					Mul(f[d], pw(P, s[c])); //					printf(&quot;%lld\n&quot;, f[d]); 				&#125;			&#125;			g[d]=f[d]; 			for(D=2*d; D&lt;=m; D+=d) Mul(g[d], pw(g[D], mo-2)); //		&#125;//		lstlim=lim; //		printf(&quot;%lld : %lld %lld %lld\n&quot;, d, f[d], g[d], pw(g[d], d)); 		Mul(ans, pw(g[d], d)); 	&#125;	Mod(ans); 	printf(&quot;%lld&quot;, ans); 	return 0;&#125;

平面图欧拉公式应用：1026T2

本文搬运自本人高中时期CSDN博客，若图片加载不出来，可到原文查看：https://blog.csdn.net/zhangtingxiqwq/article/details/134063018

http://cplusoj.com/d/senior/p/SS231026B
考虑如何维护黑色连通块恰为1这个条件。我们可以直接运用平面图的欧拉公式。
对于“空腔”这个条件，我们可以先预处理，然后通过two-pointers+桶来实现
#include&lt;bits/stdc++.h&gt;using namespace std;#define int long longinline int read()&#123;int x=0,f=1;char ch=getchar(); while(ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if(ch==&#x27;-&#x27;)f=-1;ch=getchar();&#125;while(ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=(x&lt;&lt;1)+(x&lt;&lt;3)+(ch^48);ch=getchar();&#125;return x*f;&#125;#define Z(x) (x)*(x)#define pb push_back//mt19937 rand(time(0));//mt19937_64 rand(time(0));//srand(time(0));#define N 310//#define M//#define mostruct node &#123;	int top, l, r;  &#125;;int n, m, i, j, k, T;int ans, S[N][N], f[N][N], g[N][N], h[N][N]; int a[N], b[N], c[N], e[N], p[N], l, r, sum; int bin[N*N*2], mx[N], mnX[N*N], mxX[N*N], mnY[N*N], mxY[N*N]; int vis[N][N], tot, flg[N*N]; int dx[4]=&#123;0, 0, 1, -1&#125;; int dy[4]=&#123;1, -1, 0, 0&#125;; char s[N][N]; vector&lt;node&gt;G[N]; //vector&lt;int&gt;E[N]; void dfs(int x, int y) &#123;	vis[x][y]=1; 	mnX[tot]=min(mnX[tot], x); mxX[tot]=max(mxX[tot], x); 	mnY[tot]=min(mnY[tot], y); mxY[tot]=max(mxY[tot], y); 	if(x==1 || y==1 || x==n || y==m) flg[tot]=1; 	for(int k=0; k&lt;4; ++k) &#123;		int newx=x+dx[k], newy=y+dy[k]; 		if(newx&lt;1 || newy&lt;1 || newx&gt;n || newy&gt;m) continue; 		if(vis[newx][newy]) continue; 		if(s[newx][newy]!=&#x27;0&#x27;) continue; 		dfs(newx, newy); 	&#125;&#125;signed main()&#123;//	freopen(&quot;in.txt&quot;, &quot;r&quot;, stdin);//	freopen(&quot;out.txt&quot;, &quot;w&quot;, stdout); 		freopen(&quot;village.in&quot;, &quot;r&quot;, stdin);	freopen(&quot;village.out&quot;, &quot;w&quot;, stdout);//	T=read();//	while(T--) &#123;////	&#125;	memset(mnX, 0x3f, sizeof(mnX)); 	memset(mnY, 0x3f, sizeof(mnY)); 	n=read(); m=read(); 	for(i=1; i&lt;=n; ++i) scanf(&quot;%s&quot;, s[i]+1); 	for(i=1; i&lt;=n; ++i) for(j=1; j&lt;=m; ++j) 		if(s[i][j]==&#x27;0&#x27; &amp;&amp; !vis[i][j]) ++tot, dfs(i, j); 	for(i=1; i&lt;=tot; ++i) &#123;		if(flg[i]) continue; //		printf(&quot;[%lld %lld] [%lld %lld]
&quot;, mnX[i], mxX[i], mnY[i], mxY[i]); 		G[mxX[i]+1].pb(&#123;mnX[i]-1, mnY[i], mxY[i]&#125;); 	&#125;		for(i=1; i&lt;=n; ++i) for(j=1; j&lt;=m; ++j) s[i][j]-=&#x27;0&#x27;; 	//	for(i=1; i&lt;=n; ++i, printf(&quot;
&quot;)) //		for(j=1; j&lt;=m; ++j) printf(&quot;%lld &quot;, s[i][j]); //	printf(&quot;
&quot;); 	for(j=1; j&lt;=m; ++j) 		for(i=1; i&lt;=n; ++i) &#123;			f[i][j]=f[i-1][j]; 			if(s[i][j] &amp;&amp; s[i-1][j]) ++f[i][j]; 			g[i][j]=g[i-1][j]; 			if(s[i][j] &amp;&amp; s[i][j+1]) ++g[i][j]; 			h[i][j]=h[i-1][j]; 			if(s[i][j] &amp;&amp; s[i-1][j] &amp;&amp; s[i][j+1] &amp;&amp; s[i-1][j+1])			 	++h[i][j]; 			S[i][j]=S[i-1][j]; 			if(s[i][j]) ++S[i][j]; 		&#125;//	for(i=1; i&lt;=n; ++i, printf(&quot;
