&quot;)) //		for(j=1; j&lt;=m; ++j) printf(&quot;%lld &quot;, g[i][j]); //	printf(&quot;
&quot;); 				for(l=1; l&lt;=n; ++l) &#123;		memset(mx, 0, sizeof(mx)); 		for(r=l; r&lt;=n; ++r) &#123;			for(auto t : G[r]) if(t.top&gt;=l) &#123;				mx[t.r+1]=max(mx[t.r+1], t.l); 			&#125;			for(i=1; i&lt;=m; ++i) &#123;				p[i]=S[r][i]-S[l-1][i]; 				a[i]=f[r][i]-f[l][i]; 				b[i]=g[r][i]-g[l-1][i]; 				c[i]=h[r][i]-h[l][i]; 				e[i]=p[i]-a[i]-b[i]+c[i]; 				e[i]+=e[i-1]; 			&#125;//			printf(&quot;# [%lld %lld]
&quot;, l, r); //			for(i=1; i&lt;=m; ++i) printf(&quot;%lld &quot;, mx[i]); printf(&quot;
&quot;); 			bin[N*N]++; j=0; 			for(i=1; i&lt;=m; ++i) &#123;				while(j+1&lt;mx[i]) bin[e[j]+N*N]--, ++j; //				printf(&quot;[%d %d]
&quot;, j, i); 				k=e[i-1]+p[i]-a[i]-1; 				ans+=bin[k+N*N]; 				bin[e[i]+N*N]++; 							&#125;			while(j&lt;=m) bin[e[j]+N*N]--, ++j; //			for(i=1; i&lt;=m; ++i) &#123;//				// p-a-b+c=d+1//			&#125;		&#125;	&#125;			printf(&quot;%lld&quot;, ans); 	return 0;&#125;

数学+分类讨论+构造：1102T3

本文搬运自本人高中时期CSDN博客，若图片加载不出来，可到原文查看：https://blog.csdn.net/zhangtingxiqwq/article/details/134191475

http://cplusoj.com/d/senior/p/SS231102C
首先可以通过枚举逆序对点的贡献推出无解情况为 n mod 4&gt;1n  mod 4 &gt; 1nmod4&gt;1
然后构造可以按 n mod 3n mod 3nmod3 进行分类
#include&lt;bits/stdc++.h&gt;using namespace std;#ifdef LOCAL #define debug(...) fprintf(stdout, ##__VA_ARGS__)#else #define debug(...) void(0)#endif#define int long longinline int read()&#123;int x=0,f=1;char ch=getchar(); while(ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if(ch==&#x27;-&#x27;)f=-1;ch=getchar();&#125;while(ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=(x&lt;&lt;1)+(x&lt;&lt;3)+(ch^48);ch=getchar();&#125;return x*f;&#125;#define Z(x) (x)*(x)#define pb push_back//mt19937 rand(time(0));//mt19937_64 rand(time(0));//srand(time(0));#define N 2000010//#define M//#define moint n, m, i, j, k, T;int a[N], b[N], mp[N]; vector&lt;int&gt;v[N]; void lian(int *a, int *b, int x, int y) &#123;	a[x]=y; b[y]=x; &#125;void fenzhi(int n, int l, int r, int op, int *a, int *b) &#123;//	debug(&quot;%lld [%lld %lld] %lld
&quot;, n, l, r, op); 	int x, i, j, k, p=l-1; 	if(!n) return ; 	if(n==1) return a[l]=b[l]=l, void(); 	if(op==0) &#123;		x=(n-1)/3; 				if(n&lt;=8) &#123;//			debug(&quot;&gt;&gt; %lld
