 1] - &#x27;a&#x27;], i + 1); //		debug(&quot;%lld -&gt; %lld[%c] | %lld\n&quot;, x, ch[x][str[i] - &#x27;a&#x27;], str[i], i); //		if(str[i + 2]) A.add(x, son[x][str[i + 1] - &#x27;a&#x27;], 1); 		&#125;	void bfs() &#123;		q.push(1); fail[1] = 0; fail[0] = 1; 		while(!q.empty()) &#123;			int u = q.front(), v; q.pop(); 			for(i = 0; i &lt; 26; ++i) &#123;				if(!(v = ch[u][i]) || fail[v]) continue; 				k = fail[u]; 				fail[v] = (ch[k][i] ? ch[k][i] : 1); 				End[v] |= End[fail[v]]; 				for(j = 0; j &lt; 26; ++j) 					if(!ch[v][j]) ch[v][j] = ch[fail[v]][j]; 				q.push(v); 			&#125;		&#125;	&#125;	void run(int x) &#123;		int k = 26; vis[x] = 1; 		for(int i = 0; i &lt; 26; ++i) &#123;//			if(ch[x][i]) debug(&quot;%lld --&gt; %lld\n&quot;, x, ch[x][i]); 			if(ch[x][i] &gt; 1) &#123;				--k; 				if(!End[ch[x][i]]) A.add(x, ch[x][i], 1); 				if(!vis[ch[x][i]]) run(ch[x][i]); 			&#125;		&#125;		A.add(x, rt, k); 	&#125;&#125;Tr;signed main()&#123;	#ifdef LOCAL	  freopen(&quot;in.txt&quot;, &quot;r&quot;, stdin);	  freopen(&quot;out.txt&quot;, &quot;w&quot;, stdout);	#endif//	srand(time(NULL));//	T = read();//	while(T--) &#123;////	&#125;	int Times; 	Times = read(); m = read(); 	rt = n = 1; 	for(i = 1; i &lt;= m; ++i) &#123;		scanf(&quot;%s&quot;, str + 1); 		Tr.add(Tr.ch[rt][str[1] - &#x27;a&#x27;], 1); //		A.add(rt, Tr.ch[rt][str[1] - &#x27;a&#x27;], 1); 	&#125;	Tr.bfs(); 	Tr.run(rt); //	A.print(); 	Run(Times); 	return 0;&#125;

Hexo中正文字体太小了？可以使用如下方法自定义CSS调整：

在 /themes/butterfly/source/css/ 目录下创建一个 custom.css 的文件
写入以下代码：

/* 调整文章正文字体大小 */.post-content &#123;    font-size: 20px; /* 修改为你想要的大小, 20px我认为很合适，但还不知道手机上兼不兼容 */&#125;

在Butterfly的 _config.yml 文件中，搜索 inject 选型，修改为：

