题目链接
首先，环内的节点必然可以至少存在两条路径到达，所以我们不用考虑环内的节点，可以先对无向图缩点。
剩下的节点必然构成一棵树，我们只需要将叶子节点两两配对。因为这样其上面的所有父亲节点都可以通过它下面的叶子节点形成环。
Code
// Problem: #10098. 「一本通 3.6 例 1」分离的路径// Contest: LibreOJ// URL: https://loj.ac/p/10098// Memory Limit: 64 MB// Time Limit: 1000 ms// // Powered by CP Editor (https://cpeditor.org)#include&lt;bits/stdc++.h&gt;using namespace std;#define int long longinline int read()&#123;int x=0,f=1;char ch=getchar();while(ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if(ch==&#x27;-&#x27;)f=-1;ch=getchar();&#125;while(ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=(x&lt;&lt;1)+(x&lt;&lt;3)+(ch^48);ch=getchar();&#125;return x*f;&#125;#define M 10010//#define mo#define N 5010struct node&#123;	int x, y, n; &#125;d[M*2]; int n, m, i, j, k; int h[N], f[N], c[N], dep[N], rd[N]; int lf, u, v; void cun(int x, int y)&#123;	d[++k].x=x; d[k].y=y; 	d[k].n=h[x];  h[x]=k; &#125;int fa(int x)&#123;	if(f[x]==x) return x; 	return f[x]=fa(f[x]); &#125;void dfs(int x)&#123;	for(int g=h[x]; g; g=d[g].n)	&#123;		if(c[g]) continue; 		c[((g-1)^1)+1]=c[((g-1)^1)+1]=1; 		int y=d[g].y; 		if(!dep[y])		&#123;			dep[y]=dep[x]+1; 			dfs(y); 		&#125;		if(dep[fa(y)]&gt;0) 		&#123;			if(dep[f[y]]&lt;dep[fa(x)]) f[f[x]]=f[y]; 			else f[f[y]]=f[x]; 		&#125;	&#125;	dep[x]=-1; &#125;signed main()&#123;//	freopen(&quot;tiaoshi.in&quot;, &quot;r&quot;, stdin); //	freopen(&quot;tiaoshi.out&quot;, &quot;w&quot;, stdout); 	n=read(); m=read(); 	for(i=1; i&lt;=m; ++i)	&#123;		u=read(); v=read(); 		cun(u, v); cun(v, u); 	&#125;	for(i=1; i&lt;=n; ++i) f[i]=i; 	for(i=1; i&lt;=n; ++i)		if(!dep[i]) 			dep[i]=1, dfs(1); 	for(i=1; i&lt;=n; ++i) fa(i); 	// for(i=1; i&lt;=n; ++i) printf(&quot;%lld &quot;, f[i]); 	// printf(&quot;\n&quot;); 	for(i=1; i&lt;=m; ++i)	&#123;		if(f[d[i*2].x]!=f[d[i*2].y]) 			++rd[f[d[i*2].x]], ++rd[f[d[i*2].y]]; 	&#125;	for(i=1; i&lt;=n; ++i)		if(f[i]==i&amp;&amp;rd[i]==1) ++lf; 	printf(&quot;%lld&quot;, (lf+1)/2); 	return 0; &#125;

