// Problem: #10100. 「一本通 3.6 练习 1」网络// Contest: LibreOJ// URL: https://loj.ac/p/10100// Memory Limit: 10 MB// Time Limit: 1000 ms// // Powered by CP Editor (https://cpeditor.org)#include&lt;bits/stdc++.h&gt;using namespace std;//#define int long longinline int read()&#123;int x=0,f=1;char ch=getchar();while(ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if(ch==&#x27;-&#x27;)f=-1;ch=getchar();&#125;while(ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=(x&lt;&lt;1)+(x&lt;&lt;3)+(ch^48);ch=getchar();&#125;return x*f;&#125;//#define mo#define N 110struct node&#123;	int x, y, n; &#125;d[N*N*2]; int n, m, i, j, k; int x, y, z, ans; int h[N], c[N]; char ch; void cun(int x, int y)&#123;	d[++k].x=x; d[k].y=y; 	d[k].n=h[x]; h[x]=k; &#125;void init()&#123;	m=i=j=k=x=y=z=ans=ch=0; 	memset(h, 0, sizeof(h)); 	memset(c, 0, sizeof(c)); 	memset(d, 0, sizeof(d)); &#125;void dfs(int x)&#123;	for(int g=h[x]; g; g=d[g].n)	&#123;		int y=d[g].y; 		if(c[y]) continue; 		c[y]=1; 		dfs(y); 	&#125;&#125;signed main()&#123;//	freopen(&quot;tiaoshi.in&quot;,&quot;r&quot;,stdin);//	freopen(&quot;tiaoshi.out&quot;,&quot;w&quot;,stdout);	n=read(); 	while(n)	&#123;		init(); 		scanf(&quot;%d&quot;, &amp;i); 		while(i) 		&#123;			scanf(&quot;%d%c&quot;, &amp;j, &amp;ch); 			// printf(&quot;%d %d\n&quot;, i, j); 			cun(i, j); cun(j, i); 			while(ch&gt;=32)			&#123;				scanf(&quot;%d%c&quot;, &amp;j, &amp;ch); 				// printf(&quot;%d %d\n&quot;, i, j); 				cun(i, j); cun(j, i); 			&#125;			scanf(&quot;%d&quot;, &amp;i); 			// printf(&quot;%d\n&quot;, i); 		&#125;		i=k=0; 		for(j=1; j&lt;=n; ++j) 			if(!c[j]) c[j]=1, dfs(j), ++k; 		// printf(&quot;k:%d\n&quot;, k); 		for(i=1; i&lt;=n; ++i)		&#123;			memset(c, 0, sizeof(c)); 			c[i]=1; m=0; 			for(j=1; j&lt;=n; ++j) 				if(!c[j]) c[j]=1, dfs(j), ++m; 			if(m!=k) ++ans; 			// printf(&quot;m:%d\n&quot;, m); 		&#125;		printf(&quot;%d\n&quot;, ans); 		n=read(); 	&#125;	return 0;&#125;
