从1开始从小到大考虑，用set维护每个数左右的扩散范围，然后答案为这个数的区间就是左端点个数 ×\times× 右端点个数。
Code
// Problem: AT2060 [AGC005B] Minimum Sum// Contest: Luogu// URL: https://www.luogu.com.cn/problem/AT2060// Memory Limit: 250 MB// Time Limit: 2000 ms// // Powered by CP Editor (https://cpeditor.org)#include&lt;bits/stdc++.h&gt;using namespace std;#define int long longinline int read()&#123;int x=0,f=1;char ch=getchar();while(ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if(ch==&#x27;-&#x27;)f=-1;ch=getchar();&#125;while(ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=(x&lt;&lt;1)+(x&lt;&lt;3)+(ch^48);ch=getchar();&#125;return x*f;&#125;//#define mo//#define M//#define Mstruct node&#123;	int x, id; &#125;a[200010]; int n, m, i, j, k; set&lt;int&gt;s; set&lt;int&gt;::iterator it;set&lt;int&gt;::iterator iw; int ans, l, r; bool cmp(node x, node y)&#123;	return x.x&lt;y.x; &#125;signed main()&#123;//	freopen(&quot;tiaoshi.in&quot;,&quot;r&quot;,stdin);//	freopen(&quot;tiaoshi.out&quot;,&quot;w&quot;,stdout);	n=read(); 	for(i=1; i&lt;=n; ++i) 		a[i].x=read(), a[i].id=i; 	sort(a+1, a+n+1, cmp); 	s.insert(0); s.insert(n+1); 	for(i=1; i&lt;=n; ++i)	&#123;		// printf(&quot;&gt; %lld %lld\n&quot;, a[i].x, a[i].id); 		it = s.upper_bound(a[i].id);		r=*it;		it--;		l=*it; 		k=max((long long)0, r-l-1); 		++l; --r; 		// printf(&quot;%lld %lld %lld\n&quot;, l, r, k); 		ans+=a[i].x*max((long long)0, (a[i].id-l+1)*(r-a[i].id+1)); 		s.insert(a[i].id); 	&#125;	printf(&quot;%lld&quot;, ans); 	return 0;&#125;
